SELECT COUNT(DISTINCT document_id)
FROM documents
WHERE content LIKE '%unprovoked attack%';

SELECT * 
FROM n_grams
WHERE document_id IN (SELECT document_id FROM documents WHERE user_id = 0);

SELECT COUNT(DISTINCT ngram) AS ngram_count
FROM n_grams
WHERE ngram_length > 2;

SELECT DISTINCT document_id, sentiment_score
FROM n_grams
WHERE ngram = 'unprovoked attack';

SELECT tags 
FROM documents 
WHERE document_id > 0;

SELECT document_id, last_modified_date
FROM documents
WHERE document_status = 'pending' AND last_modified_date > '2023-01-03';

SELECT ngram, ngram_length, frequency
FROM n_grams
WHERE frequency > (SELECT AVG(frequency) FROM n_grams);

SELECT DISTINCT user_name, email
FROM users
WHERE role = 'admin';
